// --- Styles ---
const styles = {
  container: {
    position: 'relative' as const,
    width: '100%',
    maxWidth: '1200px',
    margin: '0 auto',
    fontFamily: 'Arial, sans-serif',
  },
  svg: {
    position: 'absolute',
    width: '100%',
    height: 'auto',
    // ViewBox roughly covers the bounding box of Russia
    viewBox: "0 0 1000 600",
    backgroundColor: '#f0f4f8',
    borderRadius: '8px',
  },
  regionPath: {
    fill: '#e2e8f0',
    stroke: '#ffffff',
    strokeWidth: 1,
    transition: 'fill 0.2s ease',
    cursor: 'pointer',
  },
  regionPathHover: {
    fill: '#3b82f6', // Blue highlight
  },
  tooltip: {
    position: 'absolute' as const,
    backgroundColor: 'rgba(0, 0, 0, 0.85)',
    color: '#fff',
    padding: '12px',
    borderRadius: '6px',
    fontSize: '14px',
    pointerEvents: 'none' as const, // Crucial: lets mouse events pass through to the map
    zIndex: 10,
    boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
    minWidth: '200px',
  },
  tooltipTitle: {
    fontWeight: 'bold' as const,
    marginBottom: '4px',
    fontSize: '16px',
    borderBottom: '1px solid #555',
    paddingBottom: '4px',
  },
  tooltipRow: {
    display: 'flex',
    justifyContent: 'space-between',
    marginTop: '4px',
    fontSize: '13px',
    color: '#ccc',
  }
};

function Map3() {
  const [hoveredRegion, setHoveredRegion] = useState<RegionData | null>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<SVGSVGElement | null>(null)

  function drawPoints() {
    const points: { x: number; y: number }[] = []
    const pathElements = mapRef.current?.querySelectorAll("g");
    const icons = []

    if (pathElements) {
      for (let i = 0; i < pathElements.length; i++) {
        const path = pathElements[i].firstChild as SVGPathElement | null
        if (path) {
          const bbox = path.getBBox()
        const pos = {
          x: bbox.x + bbox.width / 2 - 12.5,
          y: bbox.y + bbox.height / 2 - 12.5
        }

        const f = pathElements[i].querySelector(".f") as SVGForeignObjectElement | null
        if(f) {
          f.setAttribute('x', String(pos.x))
          f.setAttribute('y', String(pos.y))
        }


      }
    }

  }
  }
  useEffect(() => {
    drawPoints()
  }, [])

  function renderSvgMap() {
    return (
      <svg ref={mapRef} width="1920" height="1080">
        {MOCK_REGIONS.map((region, idx) => {
          const reg = (
            <g className='gg'>
            <path
              className='region'
              key={region.id}
              d={region.path}
              style={{
                ...styles.regionPath,
                ...(hoveredRegion?.id === region.id ? styles.regionPathHover : {})
              }}
              onMouseEnter={() => handleMouseEnter(region)}
              onMouseLeave={handleMouseLeave}
            />
            <foreignObject className='f' width='25' height='25'>
            <div className='point'>
              <SocialIcon style={{ width: 25, height: 25 }} />
            </div>
          </foreignObject>
        
            </g>
          )
          //console.log(reg)
          return reg
        }
        )}

      </svg>


    )
  }

  const handleMouseEnter = (region: RegionData) => {
    setHoveredRegion(region);
  };

  const handleMouseLeave = () => {
    setHoveredRegion(null);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (containerRef.current) {
      const rect = containerRef.current.getBoundingClientRect();
      setMousePos({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      });
    }
  };

  return (
    <div
      ref={containerRef}
      style={styles.container}
      onMouseMove={handleMouseMove}
    >
      {renderSvgMap()}

      {hoveredRegion && (
        <div
          style={{
            ...styles.tooltip,
            left: mousePos.x + 15, // Offset slightly from cursor
            top: mousePos.y + 15,
          }}
        >
          <div style={styles.tooltipTitle}>{hoveredRegion.name}</div>
          <div style={{ marginBottom: '8px' }}>{hoveredRegion.description}</div>

          <div style={styles.tooltipRow}>
            <span>Capital:</span>
            <span>{hoveredRegion.capital}</span>
          </div>
          <div style={styles.tooltipRow}>
            <span>Population:</span>
            <span>{hoveredRegion.population}</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default Map3